changeSet.sql:
-- Map tests to MACROSCOPY group INSERT INTO clinlims.bacteriology_test_group_mapping (id, test_id, group_type, lastupdated) SELECT nextval('clinlims.bacteriology_test_group_mapping_seq'), t.id, 'MACROSCOPY', now() FROM clinlims.test t WHERE LOWER(t.description) LIKE '%macroscopi%' AND NOT EXISTS ( SELECT 1 FROM clinlims.bacteriology_test_group_mapping btgm WHERE btgm.test_id = t.id AND btgm.group_type = 'MACROSCOPY' );
-- Map tests to MICROSCOPY group INSERT INTO clinlims.bacteriology_test_group_mapping (id, test_id, group_type, lastupdated) SELECT nextval('clinlims.bacteriology_test_group_mapping_seq'), t.id, 'MICROSCOPY', now() FROM clinlims.test t WHERE LOWER(t.description) LIKE '%microscopi%' AND NOT EXISTS ( SELECT 1 FROM clinlims.bacteriology_test_group_mapping btgm WHERE btgm.test_id = t.id AND btgm.group_type = 'MICROSCOPY' );
-- Map tests to CULTURE group (usually tests containing 'culture' or 'identification') INSERT INTO clinlims.bacteriology_test_group_mapping (id, test_id, group_type, lastupdated) SELECT nextval('clinlims.bacteriology_test_group_mapping_seq'), t.id, 'CULTURE', now() FROM clinlims.test t WHERE (LOWER(t.description) LIKE '%culture%' OR LOWER(t.description) LIKE '%identification%') AND NOT EXISTS ( SELECT 1 FROM clinlims.bacteriology_test_group_mapping btgm WHERE btgm.test_id = t.id AND btgm.group_type = 'CULTURE' );
